using Microsoft.EntityFrameworkCore;
using System.Threading.Tasks;

public class EventBookingContext : DbContext
{
    public DbSet<Event> Events { get; set; }
    public DbSet<Ticket> Tickets { get; set; }

    protected override void OnConfiguring(DbContextOptionsBuilder optionsBuilder)
    {
        optionsBuilder.UseSqlServer(@"Data Source=(localdb)\mssqllocaldb;Initial Catalog=EventBookingSystem;Integrated Security=True");
    }

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Event>().ToTable("Events");
        modelBuilder.Entity<Ticket>().ToTable("Tickets");

        modelBuilder.Entity<Event>()
            .HasMany(e => e.Tickets)
            .WithOne(t => t.Event)
            .HasForeignKey(t => t.EventId);
    }
}

public class Event
{
    public int Id { get; set; }
    public string Name { get; set; }
    public int AvailableSeats { get; set; }

    public ICollection<Ticket> Tickets { get; set; }
}

public class Ticket
{
    public int Id { get; set; }
    public int EventId { get; set; }
    public Event Event { get; set; }
    public int Quantity { get; set; }
}

public class EventBookingService
{
    private readonly EventBookingContext _context;

    public EventBookingService(EventBookingContext context)
    {
        _context = context;
    }

    public async Task<bool> PurchaseTicketsAsync(int eventId, int quantity)
    {
        var eventEntity = await _context.Events.FindAsync(eventId);

        if (eventEntity == null || eventEntity.AvailableSeats < quantity)
            return false;

        try
        {
            using (var transaction = _context.Database.BeginTransaction())
            {
                eventEntity.AvailableSeats -= quantity;
                _context.Entry(eventEntity).State = EntityState.Modified;

                var ticketEntities = new Ticket[] { };
                for (int i = 0; i < quantity; i++)
                    ticketEntities.Add(new Ticket { EventId = eventId, Quantity = 1 });

                _context.Tickets.AddRange(ticketEntities);
                await _context.SaveChangesAsync();

                transaction.Commit();
            }
        }
        catch
        {
            return false;
        }

        return true;
    }
}